// Pseudo-sampler for per-tenant tracing
class TenantSampler {
  constructor(fetchRate) {
    this.fetchRate = fetchRate; // function(tenant) -> rate
    this.cache = new Map(); // tenant -> {rate, expiry}
  }
  getRate(tenant) {
    const entry = this.cache.get(tenant);
    if (entry && entry.expiry > Date.now()) return entry.rate;
    // fetch from Consul KV here, then cache for 5s
    const rate = this.fetchRate(tenant) ?? 20;
    this.cache.set(tenant, { rate, expiry: Date.now() + 5000 });
    return rate;
  }
  shouldSample(tenant) {
    const rate = this.getRate(tenant);
    return Math.random() * 100 < rate;
  }
}
