// Pseudo: token bucket per tenant with 60 rpm
const limits = JSON.parse(fs.readFileSync('/etc/config/tenant-rate-limits.json','utf8'));
const buckets = new Map();
function allow(tenant){
  const now = Date.now();
  let b = buckets.get(tenant);
  if(!b){ b = {tokens: limits[tenant]||0, last: now}; buckets.set(tenant,b); }
  // simplistic: refill 1 token per second for 60s window
  const elapsed = (now - b.last)/1000; b.last = now; b.tokens = Math.min((limits[tenant]||0), b.tokens + elapsed);
  if(b.tokens >= 1){ b.tokens--; return true; }
  return false;
}
```

