class FlagCache {
  constructor(redis, ttlSeconds = 120) {
    this.cache = new Map();
    this.ttlSeconds = ttlSeconds;
    this.redis = redis;

    redis.subscribe('tenant-flags', (err, count) => {
      if (err) console.error('Subscribe error:', err);
    });

    redis.on('message', (channel, message) => {
      if (channel === 'tenant-flags') {
        const { tenantId } = JSON.parse(message);
        this.cache.delete(tenantId);
      }
    });
  }

  async getFlag(tenantId, feature) {
    const key = `${tenantId}:${feature}`;
    const entry = this.cache.get(key);

    if (entry && Date.now() < entry.expiresAt) {
      return entry.value;
    }

    const value = await this.redis.hget(`flags:${tenantId}`, feature);
    this.cache.set(key, { value: JSON.parse(value), expiresAt: Date.now() + this.ttlSeconds * 1000 });
    return JSON.parse(value);
  }
}
```

