// Tenant-aware logger
const fs = require('fs');
let cfg = JSON.parse(fs.readFileSync('/config/tenant-logging.json','utf8'));

function log(tenant, level, entry) {
  const logLevel = cfg[tenant] || 'info';
  if (shouldLog(level, logLevel)) {
    console.log(JSON.stringify({
      tenant_id: tenant,
      level: level,
      timestamp: new Date().toISOString(),
      ...entry
    }));
  }
}

function shouldLog(requested, configured) {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  return levels[requested] >= levels[configured];
}
```

