// Token bucket implementation per tenant
async function allow(tenantId, limit) {
  const window = Math.floor(Date.now() / 60000);
  const key = `ratelimit:${tenantId}:${window}`;

  const current = await redis.incr(key);
  if (current === 1) {
    await redis.expire(key, 60);
  }

  return current <= limit;
}

// Rate limit middleware with dynamic config reload
const ratelimit = {
  scheme: 'tokenbucket',
  store: 'redis',
  key: '${header:X-Tenant}',
  burst: 100,
