const express = require('express');
const { NodeSDK } = require('@opentelemetry/sdk-node');
const { OTLPTraceExporter } = require('@opentelemetry/exporter-trace-otlp-grpc');
const { HttpInstrumentation } = require('@opentelemetry/instrumentation-http');
const { ExpressInstrumentation } = require('@opentelemetry/instrumentation-express');
const { Resource } = require('@opentelemetry/resources');
const { ATTR_SERVICE_NAME, ATTR_SERVICE_VERSION } = require('@opentelemetry/semantic-conventions');
const { trace, context, SpanStatusCode } = require('@opentelemetry/api');

const sdk = new NodeSDK({
  resource: new Resource({
    [ATTR_SERVICE_NAME]: process.env.OTEL_SERVICE_NAME || 'tenant-api',
    [ATTR_SERVICE_VERSION]: process.env.OTEL_RESOURCE_ATTRIBUTES?.split('=')[1] || '1.0.0',
  }),
  traceExporter: new OTLPTraceExporter({
    url: `${process.env.OTEL_EXPORTER_OTLP_ENDPOINT}/opentelemetry.proto.collector.trace.v1.TraceService/Export`,
  }),
  instrumentations: [
    new HttpInstrumentation(),
    new ExpressInstrumentation(),
  ],
});

sdk.start();

const app = express();

app.use((req, res, next) => {
  const tenant = req.headers['x-tenant'] || 'unknown';
  req.tenant = tenant;

  const currentSpan = trace.getActiveSpan();
  if (currentSpan) {
    currentSpan.setAttribute('x-tenant', tenant);
    currentSpan.setAttribute('tenant.id', tenant);
  }
  next();
});

app.get('/api/resource', (req, res) => {
  const tracer = trace.getTracer('tenant-api');

  tracer.startActiveSpan('fetch-resource', (span) => {
    try {
      span.setAttribute('x-tenant', req.tenant);
      span.setAttribute('http.method', req.method);
      span.setAttribute('http.route', '/api/resource');

      span.addEvent('db-query-start', { 'db.system': 'postgresql' });

      const resourceData = { tenant: req.tenant, data: 'resource-data', timestamp: Date.now() };

      span.addEvent('db-query-complete');
      res.json(resourceData);
      span.setStatus({ code: SpanStatusCode.OK });
    } catch (error) {
      span.setStatus({ code: SpanStatusCode.ERROR, message: error.message });
      span.recordException(error);
      res.status(500).json({ error: 'Internal server error' });
    } finally {
      span.end();
    }
  });
});

app.get('/health', (req, res) => {
  res.json({ status: 'healthy', service: 'tenant-api' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`API running on port ${PORT}`);
  console.log(`OTEL Exporter endpoint: ${process.env.OTEL_EXPORTER_OTLP_ENDPOINT}`);
});

process.on('SIGTERM', async () => {
  console.log('Shutting down gracefully...');
  await sdk.shutdown();
  process.exit(0);
});
```

